__declspec(dllexport) void cvm_flush_key(const H key) {
    H h;
    if (!key) return;
    cvm_resolve_payload_hash(key, h);
    {
        CacheSlot *s = &slots[primary_idx];
        if (!s->on || !same(s->key, key)) return;
        upload(s->data, s->len, h);
